# Let me check if block dot patterns match pattern hole patterns under some transformation
# Maybe the dot pattern IS the hole pattern, or a rotation/reflection of it

# Block 4 dot pattern (inner 6x6 - but only showing the inner area excluding the block's own border):
# The inner 6x6 grid of the block (offset by 1 for the block border)
# actually the block IS 8x8 and the pattern is 6x6 placed at offset (1,1)

# So the relevant grid is the 6x6 pattern area = block rows 1-6, cols 1-6
# A dot at block (r,c) with r in [1,6] and c in [1,6] → pattern (r-1, c-1)

for key, binfo in blocks_info.items():
    # Create 6x6 dot pattern
    dot_grid = np.zeros((6,6), dtype=int)
    for r,c in binfo['dots']:
        if 1 <= r <= 6 and 1 <= c <= 6:
            dot_grid[r-1, c-1] = 1

    print(f"Block {key} (color {binfo['color']}) dot pattern:")
    for row in dot_grid: print(''.join(str(x) for x in row))

    # Check against each pattern's hole pattern
    for pcolor, pinfo in patterns_info.items():
        hole_grid = (np.array(pinfo['pattern']) == bg1).astype(int)
        if np.array_equal(dot_grid, hole_grid):
            print(f"  EXACT MATCH with pattern {pcolor}!")
        # Check rotations and reflections
        for k in range(4):
            rotated = np.rot90(dot_grid, k)
            if np.array_equal(rotated, hole_grid):
                print(f"  MATCH with pattern {pcolor} (rot90 x {k})!")
            if np.array_equal(np.fliplr(rotated), hole_grid):
                print(f"  MATCH with pattern {pcolor} (rot90 x {k} + fliplr)!")
    print()

