# Now let's implement the matching algorithm
# For each pattern, classify based on which block column band or row band it overlaps

def match_patterns_to_blocks(bg, blocks, patterns, block_reg, block_rows, block_cols):
    # Block grid position
    grid_r1, grid_c1 = block_reg['r1'], block_reg['c1']
    grid_r2, grid_c2 = block_reg['r2'], block_reg['c2']

    # Block dimensions
    block_h = blocks[0]['h']
    block_w = blocks[0]['w']

    # Column bands: cols grid_c1 + j*block_w to grid_c1 + (j+1)*block_w - 1
    # Row bands: rows grid_r1 + i*block_h to grid_r1 + (i+1)*block_h - 1

    def get_col_band(c_center):
        """Which block column band does this center fall in?"""
        rel_c = c_center - grid_c1
        if 0 <= rel_c < block_cols * block_w:
            return int(rel_c // block_w)
        return None

    def get_row_band(r_center):
        """Which block row band does this center fall in?"""
        rel_r = r_center - grid_r1
        if 0 <= rel_r < block_rows * block_h:
            return int(rel_r // block_h)
        return None

    # Classify patterns
    row_aligned = []  # (pattern, row_band)
    col_aligned = []  # (pattern, col_band)
    neither = []

    for p in patterns:
        r_center = (p['r1'] + p['r2']) / 2
        c_center = (p['c1'] + p['c2']) / 2
        rb = get_row_band(r_center)
        cb = get_col_band(c_center)

        if rb is not None and cb is None:
            row_aligned.append((p, rb))
        elif cb is not None and rb is None:
            col_aligned.append((p, cb))
        elif rb is not None and cb is not None:
            # Both: treat as col-aligned? Or need special handling
            col_aligned.append((p, cb))
        else:
            neither.append(p)

    print(f"  Row-aligned: {[(p['color'], rb) for p, rb in row_aligned]}")
    print(f"  Col-aligned: {[(p['color'], cb) for p, cb in col_aligned]}")
    print(f"  Neither: {[p['color'] for p in neither]}")

    # Build block grid lookup
    block_grid = {}
    for b in blocks:
        block_grid[(b['bi'], b['bj'])] = b

    # Assignment
    assigned = {}  # (bi, bj) → pattern

    # Step 1: Row-aligned patterns first
    for p, rb in sorted(row_aligned, key=lambda x: x[0]['r1']):
        # Find leftmost available column in row rb
        for bj in range(block_cols):
            if (rb, bj) not in assigned:
                block_color = block_grid[(rb, bj)]['color']
                if p['color'] != block_color:
                    assigned[(rb, bj)] = p
                    break

    # Step 2: Col-aligned patterns (sorted by column, then by row position)
    # Group by column band
    col_groups = {}
    for p, cb in col_aligned:
        col_groups.setdefault(cb, []).append(p)

    for cb in sorted(col_groups.keys()):
        # Sort patterns by row position (top to bottom)
        pats = sorted(col_groups[cb], key=lambda p: p['r1'])
        for p in pats:
            # Find first available row in this column
            for bi in range(block_rows):
                if (bi, cb) not in assigned:
                    block_color = block_grid[(bi, cb)]['color']
                    if p['color'] != block_color:
                        assigned[(bi, cb)] = p
                        break

    # Step 3: Neither patterns to remaining blocks
    remaining_blocks = [(bi, bj) for bi in range(block_rows) for bj in range(block_cols) if (bi, bj) not in assigned]
    remaining_patterns = [p for p in neither if p not in [v for v in assigned.values()]]

    # Also check if any col-aligned patterns couldn't be assigned
    assigned_pats = set(id(v) for v in assigned.values())
    for p, cb in col_aligned:
        if id(p) not in assigned_pats:
            remaining_patterns.append(p)
    for p, rb in row_aligned:
        if id(p) not in assigned_pats:
            remaining_patterns.append(p)

    # Sort remaining by reading order
    remaining_blocks.sort()
    remaining_patterns.sort(key=lambda p: (p['r1'], p['c1']))

    for (bi, bj), p in zip(remaining_blocks, remaining_patterns):
        assigned[(bi, bj)] = p

    return assigned

# Test on training examples
for i, s in enumerate(train_samples):
    print(f"\n=== Example {i} ===")
    bg, blocks, patterns, block_reg, br, bc = analyze_grid(s['input'])
    matching = match_patterns_to_blocks(bg, blocks, patterns, block_reg, br, bc)

    block_grid = {(b['bi'], b['bj']): b for b in blocks}
    for (bi, bj), p in sorted(matching.items()):
        b = block_grid[(bi, bj)]
        print(f"  Block ({bi},{bj}) color={b['color']} ← Pattern color={p['color']}")

